/// <summary>
/// Controller class for handling the creation of unsold journals in the ETGSPAIN model.
/// This controller manages the workflow for processing unsold transactions.
/// </summary>
class ETGSPAINUnsoldJournalCreateController extends SysOperationServiceController
{    
}

Method.Source:
/// <summary>
/// Initializes a new instance of the controller and sets the service and method to be executed.
/// </summary>
protected void new()
{
    super(classStr(ETGSPAINUnsoldInventTransModifyService), methodStr(ETGSPAINUnsoldInventTransModifyService, process), SysOperationExecutionMode::Synchronous);
}

/// <summary>
/// Creates an instance of the controller with the specified arguments and execution mode.
/// </summary>
/// <param name="_args">The arguments passed to the controller.</param>
/// <param name="_executionMode">The execution mode of the operation (default is Synchronous).</param>
/// <returns>Returns an instance of <c>ETGSPAINUnsoldJournalCreateController</c>.</returns>
public static ETGSPAINUnsoldJournalCreateController construct(Args _args, SysOperationExecutionMode _executionMode = SysOperationExecutionMode::Synchronous)
{
    ETGSPAINUnsoldJournalCreateController controller = new ETGSPAINUnsoldJournalCreateController();

    controller.parmExecutionMode(_executionMode);
    controller.parmArgs(_args);

    return controller;
}

/// <summary>
/// The main method to initiate the process of creating unsold journals, invoked from a MenuItem.
/// </summary>
/// <param name="_args">The arguments passed to the main method.</param>
public static void main(Args _args)
{
    if (!_args)
    {
        throw error(Error::wrongUseOfFunction(funcName()));
    }

    if (!_args.record())
    {
        throw error(Error::wrongUseOfFunction(funcName()));
    }

    ETGSPAINUnsoldJournalCreateController   controller  = ETGSPAINUnsoldJournalCreateController::construct(_args);
    ETGSPAINUnsoldJournalCreateContract     contract    = controller.getDataContractObject();

    controller.showBatchTab(false);
    controller.parmLoadFromSysLastValue(false);

    ETGSPAINUnsoldInventTrans   etgspainUnsoldInventTrans;
    InventTransId               inventTransId;

    switch (_args.record().TableId)
    {
        case (tableNum(SalesLine)):
            SalesLine salesLine =  _args.record();
            inventTransId = salesLine.InventTransId;
            break;

        case (tableNum(PurchLine)):
            PurchLine purchLine =  _args.record();
            inventTransId = purchLine.InventTransId;
            break;

        default:
            throw error(strfmt("@SYS22828", funcName()));
    }

    //etgspainUnsoldInventTrans = ETGSPAINUnsoldInventTrans::findOrCreateByInventTransId(inventTransId, true);

    if (!etgspainUnsoldInventTrans)
    {
        throw Error("@ETGSPAINLabels:ETGSPAINUnsoldInventTransFindOrCreateError");
    }

    contract.parmETGSPAINUnsoldQty(etgspainUnsoldInventTrans.UnsoldQty);
    contract.parmRefRecId(etgspainUnsoldInventTrans.RefRecId);

    controller.startOperation();
}

